import{_ as e,o as a,c as r,ag as o}from"./chunks/framework.B9unkguw.js";const u=JSON.parse('{"title":"Logging (ArduPilot)","description":"","frontmatter":{},"headers":[],"relativePath":"ko/qgc-user-guide/setup_view/logging_ardupilot.md","filePath":"ko/qgc-user-guide/setup_view/logging_ardupilot.md"}'),d={name:"ko/qgc-user-guide/setup_view/logging_ardupilot.md"};function i(l,t,n,s,g,c){return a(),r("div",null,t[0]||(t[0]=[o('<h1 id="logging-ardupilot" tabindex="-1">Logging (ArduPilot) <a class="header-anchor" href="#logging-ardupilot" aria-label="Permalink to &quot;Logging (ArduPilot)&quot;">​</a></h1><p>The <em>Logging</em> setup page (<strong>Vehicle Config &gt; Logging</strong>) is available for ArduPilot vehicles and allows you to configure how and what the flight controller logs.</p><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><p>All parameters are optional — controls for parameters not supported by the connected firmware are hidden automatically.</p><h3 id="storage" tabindex="-1">Storage <a class="header-anchor" href="#storage" aria-label="Permalink to &quot;Storage&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>LOG_BACKEND_TYPE</code></td><td>Which backends are active: SD card file, MAVLink stream, and/or onboard flash (bitmask).</td></tr><tr><td><code>LOG_BITMASK</code></td><td>Which data groups are included in the log (bitmask).</td></tr><tr><td><code>LOG_MAX_FILES</code></td><td>Maximum number of log files retained before the oldest is rotated out.</td></tr><tr><td><code>LOG_FILE_MB_FREE</code></td><td>Minimum free SD card space (MB) that must remain available before logging begins.</td></tr></tbody></table><h3 id="rate-limits" tabindex="-1">Rate Limits <a class="header-anchor" href="#rate-limits" aria-label="Permalink to &quot;Rate Limits&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>LOG_FILE_RATEMAX</code></td><td>Maximum file logging rate (Hz). Lower this if the SD card cannot keep up.</td></tr><tr><td><code>LOG_BLK_RATEMAX</code></td><td>Maximum block (onboard flash) logging rate (Hz).</td></tr><tr><td><code>LOG_MAV_RATEMAX</code></td><td>Maximum MAVLink log stream rate (Hz).</td></tr></tbody></table><h3 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>LOG_DISARMED</code></td><td>Enable logging while the vehicle is disarmed (useful for pre-arm diagnostics).</td></tr><tr><td><code>LOG_FILE_DSRMROT</code></td><td>Rotate the log file after each disarm/rearm sequence.</td></tr><tr><td><code>LOG_REPLAY</code></td><td>Log extra data needed for EKF replay analysis.</td></tr><tr><td><code>EK3_LOG_LEVEL</code></td><td>Controls EKF3 logging verbosity (0 = full, 3 = disabled).</td></tr></tbody></table>',10)]))}const m=e(d,[["render",i]]);export{u as __pageData,m as default};
